import{_ as a,o as t,c as l,ae as n}from"./chunks/framework.BAOUhEwF.js";const m=JSON.parse('{"title":"elements/form/legend","description":"","frontmatter":{},"headers":[],"relativePath":"api/ts/elements/form/legend/README.md","filePath":"api/ts/elements/form/legend/README.md"}'),r={name:"api/ts/elements/form/legend/README.md"};function o(s,e,i,d,h,c){return t(),l("div",null,[...e[0]||(e[0]=[n('<p><a href="./../../../README.html"><strong>@vastare/fundatio v1.0.1</strong></a></p><hr><h1 id="elements-form-legend" tabindex="-1">elements/form/legend <a class="header-anchor" href="#elements-form-legend" aria-label="Permalink to &quot;elements/form/legend&quot;">​</a></h1><p>Fundatio Design Foundation: Legend element helpers.</p><h2 id="remarks" tabindex="-1">Remarks <a class="header-anchor" href="#remarks" aria-label="Permalink to &quot;Remarks&quot;">​</a></h2><p>The legend element (<code>&lt;legend&gt;</code>) represents a caption for the content of its parent <code>&lt;fieldset&gt;</code>. It is commonly used to label groups of related form controls (e.g. radio-button groups), improving clarity and accessibility.</p><p>Best-practice guidance:</p><ul><li>Use <code>&lt;legend&gt;</code> as the first child of a <code>&lt;fieldset&gt;</code> to label the group.</li><li>Keep legend text concise and meaningful (it is typically announced with grouped controls by assistive technologies).</li><li>Avoid using <code>&lt;legend&gt;</code> purely for layout; use CSS for styling/spacing.</li></ul><p>This module provides small, framework-agnostic helpers so consumers can:</p><ul><li>create <code>&lt;legend&gt;</code> elements in vanilla JS/TS without templates</li><li>apply consistent global attributes safely</li><li>use a stable &quot;enhancement&quot; hook if Fundatio ever needs runtime behavior</li></ul><p>This module has no side effects and does not mutate the DOM unless you call its functions.</p><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/HTML/Element/legend" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Web/HTML/Element/legend</a></li><li><a href="https://www.w3.org/WAI/tutorials/forms/grouping/" target="_blank" rel="noreferrer">https://www.w3.org/WAI/tutorials/forms/grouping/</a></li></ul><h2 id="type-aliases" tabindex="-1">Type Aliases <a class="header-anchor" href="#type-aliases" aria-label="Permalink to &quot;Type Aliases&quot;">​</a></h2><h3 id="attributes" tabindex="-1">Attributes <a class="header-anchor" href="#attributes" aria-label="Permalink to &quot;Attributes&quot;">​</a></h3><ul><li><a href="./type-aliases/LegendAttrs.html">LegendAttrs</a></li><li><a href="./type-aliases/StructuredAria.html">StructuredAria</a></li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h3><ul><li><a href="./variables/LEGEND_SELECTOR.html">LEGEND_SELECTOR</a></li><li><a href="./variables/LEGEND_TAG.html">LEGEND_TAG</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="dom" tabindex="-1">DOM <a class="header-anchor" href="#dom" aria-label="Permalink to &quot;DOM&quot;">​</a></h3><ul><li><a href="./functions/createLegend.html">createLegend</a></li></ul><h3 id="enhancement" tabindex="-1">Enhancement <a class="header-anchor" href="#enhancement" aria-label="Permalink to &quot;Enhancement&quot;">​</a></h3><ul><li><a href="./functions/enhanceLegends.html">enhanceLegends</a></li></ul>',24)])])}const f=a(r,[["render",o]]);export{m as __pageData,f as default};
